  const sectionRefs = useRef({});

  // Scroll reveal
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setVisibleSections((prev) => new Set([...prev, entry.target.id || entry.target.className]));
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15 }
    );

    document.querySelectorAll(".reveal").forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, []);

  // Counter animation
  useEffect(() => {
    const animateCounter = (el, target, suffix = "") => {
      const duration = 1400;
      const start = performance.now();

      const tick = (now) => {
        const p = Math.min((now - start) / duration, 1);
        const eased = 1 - Math.pow(1 - p, 3);
        const value = Math.round(eased * target);
        setCounterValues((prev) => ({ ...prev, [el]: value + suffix }));

        if (p < 1) requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);
    };

    const counterObserver = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const target = parseInt(entry.target.dataset.count, 10);
            const suffix = entry.target.dataset.suffix || "";
            const id = entry.target.id;
            if (!counterValues[id]) {
              animateCounter(id, target, suffix);
            }
            counterObserver.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.4 }
    );

    document.querySelectorAll("[data-count]").forEach((el) => {
      el.id = `counter-${el.dataset.count}`;
      counterObserver.observe(el);
    });

    return () => counterObserver.disconnect();
  }, [counterValues]);

  // Active nav link on scroll is now managed by the Header component.

  // Hero slideshow
  useEffect(() => {
    const timer = setInterval(() => {
      setActiveSlide((prev) => (prev + 1) % 3);
    }, 4200);
    return () => clearInterval(timer);
  }, []);

